import{_ as s,o as i,c as n,a}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"1.7 Building Your Custom Production Kernel","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_debugging/ch01_6.md","filePath":"en/notes/linux_kernel_debugging/ch01_6.md","lastUpdated":null}'),t={name:"en/notes/linux_kernel_debugging/ch01_6.md"};function o(r,e,l,h,p,d){return i(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="_1-7-building-your-custom-production-kernel" tabindex="-1">1.7 Building Your Custom Production Kernel <a class="header-anchor" href="#_1-7-building-your-custom-production-kernel" aria-label="Permalink to &quot;1.7 Building Your Custom Production Kernel&quot;">​</a></h1><p>At this point, I&#39;ll assume you&#39;re no longer a stranger to the basic workflow of building a Linux kernel from source: fetching the source tree, configuring, and compiling. If you feel a bit rusty or want to brush up on the details, I highly recommend flipping through <em>Linux Kernel Programming</em> or checking out the &quot;Further Reading&quot; section at the end of this chapter.</p><p>Since we&#39;re talking about a &quot;production kernel,&quot; our goal is clear: it must be stable, fast, and secure. But as we discussed in the previous section, we shouldn&#39;t just guess configurations from scratch. The smartest approach is to &quot;stand on the shoulders of giants&quot;—tuning based on an existing system&#39;s configuration (the so-called <code>localmodconfig</code> strategy). Once we have this reliable starting point, we further enhance security through &quot;hardening&quot; configurations.</p><p>Let&#39;s take the first step and lay a solid foundation.</p><h3 id="_1-7-1-fetching-the-source-and-base-configuration" tabindex="-1">1.7.1 Fetching the Source and Base Configuration <a class="header-anchor" href="#_1-7-1-fetching-the-source-and-base-configuration" aria-label="Permalink to &quot;1.7.1 Fetching the Source and Base Configuration&quot;">​</a></h3><p><strong>Goal</strong>: Set up a working directory, fetch and extract the LTS kernel source.</p><blockquote><p><strong>Why do this</strong>: In the previous section, we selected LTS version <strong>5.10.60</strong> as our baseline. To keep our environment clean, we need a dedicated working directory to store the source code and build artifacts. The <code>--directory</code> parameter of <code>tar</code> lets us place files in the right location while extracting, saving us a few extra <code>mv</code> commands.</p></blockquote><p><strong>Working Directory</strong>: User home directory</p><p><strong>Commands and Output</strong>:</p><p>First, let&#39;s set up a dedicated workshop:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> –p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/productionk</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Next, let&#39;s fetch the source. Here we use <code>wget</code> to grab the compressed archive directly, though you could also use <code>git</code> (if you don&#39;t mind a slightly longer wait):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://mirrors.edge.kernel.org/pub/linux/kernel/v5.x/linux-5.10.60.tar.xz</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Extract it:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> linux-5.10.60.tar.xz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --directory=productionk/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Enter the extracted directory and verify the version information along the way. This might seem like a boring step, but there&#39;s actually something quite interesting here:</p><p>Every version of the Linux kernel has a codename—the codename for 5.10.60 is <strong>&quot;Dare mighty things&quot;</strong>. I quite like this name; it&#39;s very fitting for what we&#39;re doing here, as we are essentially performing surgery on the very heart of the operating system.</p><h3 id="_1-7-2-generating-a-trimmed-configuration-localmodconfig" tabindex="-1">1.7.2 Generating a Trimmed Configuration (localmodconfig) <a class="header-anchor" href="#_1-7-2-generating-a-trimmed-configuration-localmodconfig" aria-label="Permalink to &quot;1.7.2 Generating a Trimmed Configuration (localmodconfig)&quot;">​</a></h3><p><strong>Goal</strong>: Use the list of modules currently running on the system to generate a tailored initial kernel configuration file.</p><blockquote><p><strong>Why do this</strong>: A full default configuration includes thousands of drivers and modules you don&#39;t need, resulting in a bloated and slow kernel. The magic of <code>localmodconfig</code> is that it scans which modules are currently loaded on your system (the output of <code>lsmod</code>) and turns off everything that isn&#39;t selected. It&#39;s like performing liposuction on the kernel.</p></blockquote><p><strong>Working Directory</strong>: Kernel source root directory (<code>~/lkd_kernels/productionk/linux-5.10.60/</code>)</p><p><strong>Commands and Output</strong>:</p><p>First, generate a snapshot of the current system&#39;s modules:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">lsmod</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/lsmod.now</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Then feed this snapshot to <code>make</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LSMOD=/tmp/lsmod.now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> localmodconfig</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>⚠️ Pitfall Warning</strong> During this process, the terminal might pause and ask you a few questions (interactive interface). Don&#39;t panic—if you don&#39;t understand the specific meaning of an option, <strong>just press Enter to accept the default value</strong>, which is usually the safest bet. Our goal here is simply to get a &quot;good enough&quot; starting point, not to finalize every detail right now.</p><p>Once this step is done, you&#39;ll find a new <code>.config</code> file in the root of the source tree. This is a treasure—it&#39;s the &quot;soul&quot; of the kernel.</p><p>Back it up first, just in case we break something later and need to revert:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> –af</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/kconfig_prod01</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><blockquote><p><strong>Tip</strong>: You can always type <code>make help</code> to see all available configuration commands. If you&#39;re a veteran, you can completely use <code>make menuconfig</code> to change the interface to a style you&#39;re familiar with.</p></blockquote><h3 id="_1-7-3-kernel-hardening—the-price-of-security" tabindex="-1">1.7.3 Kernel Hardening—The Price of Security <a class="header-anchor" href="#_1-7-3-kernel-hardening—the-price-of-security" aria-label="Permalink to &quot;1.7.3 Kernel Hardening—The Price of Security&quot;">​</a></h3><p><strong>Goal</strong>: Use automated tools to check and modify the kernel configuration, enabling security hardening options.</p><p>Now we have a &quot;working&quot; configuration. But before putting it into production, we need to address a dilemma: <strong>security vs. convenience</strong>.</p><p>Many hardening features are <strong>disabled</strong> by default in the Linux kernel. Why? Because they either sacrifice performance or break compatibility with certain legacy software. But in production environments, especially for systems dedicated to debugging or running sensitive services, we lean towards &quot;security.&quot;</p><p>The problem is: even if you open <code>make menuconfig</code>, faced with thousands of options, you won&#39;t know which ones control security.</p><p>Fortunately, someone has done this dirty work for us.</p><p><strong>Introducing the Tool: kconfig-hardened-check</strong></p><p>This is actually a validator—but it works in reverse to tell you what industry-recognized security best practices are missing from your configuration. It&#39;s like a strict security auditor going down a checklist against your <code>.config</code> and ticking off items one by one.</p><p>Install and run it (using the Python script as an example here):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 假设你已经通过 pip 安装了该脚本，或者克隆了仓库</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kconfig-hardened-check.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .config</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>You&#39;ll see a ton of output, like this (excerpt):</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[+] Check: CONFIG_BUG is required: set to y</span></span>
<span class="line"><span>[+] Check: CONFIG_STRICT_KERNEL_RWX is required: set to y</span></span>
<span class="line"><span>[-] Check: CONFIG_DEBUG_LIST is suggested: NOT set (should be y)</span></span>
<span class="line"><span>[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>We don&#39;t need to dive deep into every detail of this script here (that deserves its own article). The core logic is: <strong>it tells you what you&#39;re missing, and you add it</strong>.</p><p>Based on its recommendations, I adjusted the final configuration for the production kernel. I&#39;ve placed this configuration file in this book&#39;s GitHub repository (<code>ch1/kconfig_prod01</code>); you can use it directly or as a reference.</p><h3 id="_1-7-4-compiling-and-installing" tabindex="-1">1.7.4 Compiling and Installing <a class="header-anchor" href="#_1-7-4-compiling-and-installing" aria-label="Permalink to &quot;1.7.4 Compiling and Installing&quot;">​</a></h3><p><strong>Goal</strong>: Compile the kernel, install the modules, and update the bootloader.</p><p>Now, the configuration is finally set in stone. It&#39;s time to turn this source code into that famous <strong>bzImage</strong>.</p><p><strong>Working Directory</strong>: Kernel source root directory</p><p>First, confirm how many CPU cores you have—this determines how fast we can get this done:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nproc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">4</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>I have 4 cores here. As a rule of thumb, the number following <code>make -j</code> is usually twice the number of cores. This maximizes CPU utilization while avoiding overload.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -j8</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ ... 一大段滚动的编译日志 ... ]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">BUILD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">   arch/x86/boot/bzImage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Kernel:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> is</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ready</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (#1)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>When you see the line <code>is ready</code>, you&#39;ve succeeded.</p><p>But there are two files here, and we need to clarify their relationship slightly:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rw-r--r--</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9.1M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 17:21</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arch/x86/boot/bzImage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-rwxr-xr-x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> letsdebug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  65M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Aug</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 19</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 17:21</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><strong>bzImage (9.1MB)</strong>: This is the <strong>compressed</strong> kernel image. This is the file that GRUB actually reads and boots. Don&#39;t be fooled by the <code>b</code> in the name; it doesn&#39;t stand for Big, but rather &quot;boot zImage&quot; (roughly).</li><li><strong>vmlinux (65MB)</strong>: This is the <strong>uncompressed</strong> ELF executable. <strong>Don&#39;t delete it</strong>. While it&#39;s not used for booting, it contains all the <strong>symbol information</strong>—that&#39;s our lifeline when debugging later.</li></ul><blockquote><p><strong>SICP-style aside</strong>: There&#39;s a subtle division of labor here. <code>bzImage</code> is for survival—it needs to be small enough to be loaded into memory and quickly decompressed; <code>vmlinux</code> is for understanding—it retains all the details for us to perform an autopsy when the system crashes.</p></blockquote><p>Next, install the kernel modules. This copies the compiled <code>.ko</code> files into the system&#39;s standard directory, <code>/lib/modules/$(uname -r)</code>:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modules_install</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ ... ]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  DEPMOD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.10.60-prod01</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /lib/modules/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">5.10.60-prod01/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.11.0-27-generic/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  5.8.0-43-generic/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Notice that <code>5.10.60-prod01</code> directory—that&#39;s our new turf.</p><p>The final step is to let the system &quot;know&quot; this new kernel exists. We need to generate the <code>initramfs</code> (initial RAM filesystem) and update the GRUB configuration:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Several scripts actually run behind the scenes with this command. <code>initramfs</code> is absolutely critical; it contains a minimal set of drivers and scripts responsible for preparing the hardware environment before the kernel actually mounts the root filesystem on the disk. Without it, modern systems usually won&#39;t boot.</p><h3 id="_1-7-5-first-ignition—switching-to-the-new-kernel" tabindex="-1">1.7.5 First Ignition—Switching to the New Kernel <a class="header-anchor" href="#_1-7-5-first-ignition—switching-to-the-new-kernel" aria-label="Permalink to &quot;1.7.5 First Ignition—Switching to the New Kernel&quot;">​</a></h3><p><strong>Goal</strong>: Reboot the system, select the new kernel from the GRUB menu, and verify the system is running normally.</p><p>Everything is ready; all that&#39;s left is to reboot.</p><p>But before hitting the restart button, pause for a second. Think about it: if this step succeeds, what do you expect to see?</p><p>You should see the GRUB boot menu. If your menu is normally hidden (or skips too quickly), you can call it up by mashing the <strong>Shift key</strong> (for legacy BIOS) or the <strong>Esc key</strong> (for UEFI) during boot.</p><p>You should see a new option named <strong>&quot;5.10.60-prod01&quot;</strong>.</p><p>Select it and press Enter.</p><p>If you&#39;re working in a virtual machine, like my Oracle VirtualBox here, you might also notice an issue: the resolution is wrong, or the mouse isn&#39;t automatically captured. Don&#39;t worry—that&#39;s just because VirtualBox&#39;s <strong>Guest Additions</strong> haven&#39;t been compiled for the new kernel yet. This doesn&#39;t affect kernel functionality at all; it just makes the experience slightly less polished. To avoid distractions, I usually just SSH in to get work done at this point.</p><p>If all goes well, you&#39;ll see the familiar login prompt.</p><p>Once in the system, type this command to confirm we&#39;re sitting on the new engine:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> uname</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Linux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dbg-LKD</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 5.10.60-prod01</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #1 SMP PREEMPT Thu Aug 19 17:10:00 IST 2021 x86_64 x86_64 x86_64 GNU/Linux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>That <code>5.10.60-prod01</code> suffix is the mark we made with our own hands.</p><blockquote><p><strong>Milestone Summary</strong> We now have a system running on our custom kernel. It&#39;s trimmed, hardened, and ready for action. But this is just a &quot;production kernel&quot;—it&#39;s like an agile but tight-lipped secret agent.</p><p>In the journey ahead, you&#39;ll encounter all sorts of tricky kernel-level bugs. Sometimes, you&#39;ll need to make this agent talk, or have it log every single thought process.</p><p>When that time comes, relying solely on this &quot;production kernel&quot; won&#39;t be enough.</p><p>We&#39;ll need another character—more chatty, perhaps even a bit bloated: the <strong>debug kernel</strong>.</p></blockquote>`,77)])])}const g=s(t,[["render",o]]);export{u as __pageData,g as default};
